CREATE TRIGGER [Global].[Process_History]ON [Global].[Process]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.ProcessId IS NOT NULL AND d.ProcessId IS NULL THEN 'I' 		WHEN i.ProcessId IS NOT NULL AND d.ProcessId IS NOT NULL THEN 'U' 		WHEN i.ProcessId IS NULL AND d.ProcessId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.ProcessId = d.ProcessId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Global_Process([ProcessId], [Number], [Name], [LoopNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [ProcessId], [Number], [Name], [LoopNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Global_Process([ProcessId], [Number], [Name], [LoopNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [ProcessId], [Number], [Name], [LoopNumber], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND